{
  "name": "my-vibe",
  "version": "0.1.0",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "type": "module",
  "scripts": {
    "build:rust:linux": "cargo build --target aarch64-unknown-linux-gnu --verbose && mv target/aarch64-unknown-linux-gnu/debug/my-vibe target/debug/my-vibe-linux",
    "build:rust:macos": "cargo build --verbose && mv target/debug/my-vibe target/debug/my-vibe-macos",
    "build": "tsc && echo 'Build placeholders completed.'",
    "demo": "node dist/demo.js",
    "start": "node dist/index.js"
  },
  "dependencies": {
    "@google/genai": "^1.47.0",
    "@mariozechner/pi-coding-agent": "^0.64.0",
    "@mariozechner/pi-tui": "^0.64.0",
    "@modelcontextprotocol/sdk": "^1.29.0"
  },
  "devDependencies": {
    "@types/node": "^20.5.0",
    "typescript": "^5.2.0"
  }
}

import { execSync } from 'child_process';
import * as path from 'path';
/**
 * Runs the compiled Rust binary and returns its stdout.
 * Dispatches to the appropriate binary for the current platform.
 */
export function helloRust() {
    const platform = process.platform;
    let binaryName;
    if (platform === 'darwin') {
        binaryName = 'my-vibe';
    }
    else if (platform === 'linux') {
        binaryName = 'my-vibe-linux';
    }
    else {
        throw new Error(`Unsupported platform: ${platform}`);
    }
    const binaryPath = path.resolve(__dirname, '../target/debug', binaryName);
    try {
        const output = execSync(binaryPath, { encoding: 'utf-8' });
        return output.trim();
    }
    catch (err) {
        throw new Error(`Failed to execute Rust binary: ${err}`);
    }
}

